-- ============================================================
-- TONEUP — Seed product catalog
-- Generated: 647 products from 61 brands
-- IMPORTANT: All products start with verified=false.
-- Human verification recommended before public launch.
-- ============================================================

alter table products add column if not exists verified boolean default false;
alter table products add column if not exists origin_country text;

on conflict (brand, name, shade_code) do nothing;
